import java.io.File;
import javax.imageio.ImageIO;

public class ImageConverter {
    public static void convertImage(String inputFile, String outputFile, String format) throws Exception {
        if (!format.toLowerCase().matches("jpg|jpeg|png|gif|bmp")) {
            throw new IllegalArgumentException("Unsupported image format");
        }

        try {
            Process process = Runtime.getRuntime().exec(new String[] {"convert", inputFile, "-format", format, outputFile});
            process.waitFor();
        } catch (Exception e) {
            System.out.println("Error converting image: " + e.getMessage());
            throw e;
        }
    }
}